import React from 'react'
import { Button, Card, CardContent, Divider, MenuItem, Stack, TextField } from '@mui/material';
import List from '@mui/material/List'
import ListItem from '@mui/material/ListItem'
import ListItemText from '@mui/material/ListItemText'
import ListItemAvatar from '@mui/material/ListItemAvatar'
import Avatar from '@mui/material/Avatar'
import { PageContainer } from '@/components/PageContainer'
import { StatusMessage } from '@/components/StatusMessage'
import BadgeIcon from '@mui/icons-material/Badge';
import AddBusinessIcon from '@mui/icons-material/AddBusiness';
import { CallStatus, PaginationRequest } from "@/types/api.types";
import { StateData } from '@/store';
import { BusinessResult, CreateBusinessPayload } from '@/types/business.types';
import { BusinessServices, BusinessServicesError } from '@/api';
import {BusinessCategories} from '@/constants/StaticLists';
import { useBusinessStore } from '@/store';
import { ApiComponentStateManager, ApiGlobalStateManagerPaginated } from '@/lib/api-state';
import { Link } from '@tanstack/react-router';
import { Pathname } from '@/constants/Routes';
import { submitButtonStyle } from '@/constants/ThemeConstants';

export const BusinessCreate: React.FunctionComponent = () => {
    const [formData, setFormData] = React.useState<CreateBusinessPayload>({
        name: '',
        details: '',
        category: '',
        address: '',
        pinCode: 0,
        mapLink: '',
        offer: '',
        phone: '',
        email: '',
        website: ''
    });
    const [errors, setErrors] = React.useState<Record<string, string>>({});
    const [isSubmitted, setIsSubmitted] = React.useState<boolean>(false);
    const [businessCreationResult, setBusinessCreationResult] = React.useState<StateData<BusinessResult>>({} as StateData<BusinessResult>);
    const { setBusinessStateList } = useBusinessStore();

    // Simple validation function
    const validateField = (field: string, value: any): string => {
        switch (field) {
            case 'name':
                return !value?.trim() || value.trim().length < 3 ? "Business name must be at least 3 characters" : "";
            case 'category':
                return !value?.trim() ? "Please select a business category" : "";
            case 'details':
                return !value?.trim() || value.trim().length < 3 ? "Please provide business details (min 3 characters)" : "";
            case 'phone':
                if (!value) return "Phone number is required";
                const cleanPhone = value.replace(/\D/g, '');
                return !/^[6-9]\d{9}$/.test(cleanPhone) ? "Enter valid 10-digit Indian mobile number" : "";
            case 'address':
                return !value?.trim() || value.trim().length < 3 ? "Address must be at least 3 characters" : "";
            case 'pinCode':
                return !value || value.toString().length !== 6 ? "Pin code must be a valid 6-digit number" : "";
            default:
                return "";
        }
    };

    // Handle field changes
    const handleChange = (field: string, value: any) => {
        setFormData(prev => ({ ...prev, [field]: value }));
        
        // Validate required fields only
        const requiredFields = ['name', 'category', 'details', 'phone', 'address', 'pinCode'];
        if (requiredFields.includes(field)) {
            const error = validateField(field, value);
            setErrors(prev => ({ ...prev, [field]: error }));
        }
    };

    // Check if form is valid
    const isFormValid = React.useMemo(() => {
        const requiredFields = ['name', 'category', 'details', 'phone', 'address', 'pinCode'];
        return requiredFields.every(field => {
            const value = formData[field as keyof CreateBusinessPayload];
            return validateField(field, value) === "";
        });
    }, [formData]);

    // Handle form submission
    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        
        // Validate all required fields
        const newErrors: Record<string, string> = {};
        const requiredFields = ['name', 'category', 'details', 'phone', 'address', 'pinCode'];
        
        requiredFields.forEach(field => {
            const value = formData[field as keyof CreateBusinessPayload];
            const error = validateField(field, value);
            if (error) newErrors[field] = error;
        });
        
        setErrors(newErrors);
        
        // Submit if valid
        if (Object.keys(newErrors).length === 0) {
            setIsSubmitted(true);
            // Strip empty optional strings so server-side [EmailAddress]/[Url] validators
            // don't reject "" — they only run when a value is supplied.
            const optionalStringFields: Array<keyof CreateBusinessPayload> = ['category', 'mapLink', 'offer', 'email', 'website'];
            const payload = { ...formData };
            optionalStringFields.forEach(f => {
                if (typeof payload[f] === 'string' && (payload[f] as string).trim() === '') {
                    (payload as any)[f] = undefined;
                }
            });
            ApiComponentStateManager(BusinessServices.CreateBusiness(payload), setBusinessCreationResult).then(() => {
                const paginationRequest: PaginationRequest = { pageNumber: 1, pageSize: 20 };
                ApiGlobalStateManagerPaginated(BusinessServices.GetMyBusinessList(paginationRequest), setBusinessStateList);
            });
        }
    };

    return (
        <>
            <PageContainer
                icon={<AddBusinessIcon color="primary" />}
                title="Add business"
                subtitle="Register your business so other alumni can discover and connect with you."
            >
                <Card sx={{ mb: 2 }}>
                    <CardContent>
                {businessCreationResult.status === CallStatus.Success ? (
                    <Stack direction='column' spacing={2} sx={{ margin: 2, alignItems: 'flex-start' }}>
                        <StatusMessage
                            currentStatus={CallStatus.Success}
                            successMessage={`Congratulations 🎉, your business "${businessCreationResult.data?.name}" has been added!`}
                        />
                        <Button
                            variant="contained"
                            component={Link}
                            to={Pathname.Business}
                            sx={{ textTransform: 'none', borderRadius: 2, whiteSpace: 'nowrap' }}
                        >
                            Go to My Businesses
                        </Button>
                    </Stack>
                ) : (
                    <form onSubmit={handleSubmit}>
                        <List>
                            <ListItem>
                                <ListItemAvatar>
                                    <Avatar>
                                        <BadgeIcon />
                                    </Avatar>
                                </ListItemAvatar>
                                <ListItemText primary="Add your Business" />
                            </ListItem>
                            <Stack direction='column' spacing={2} sx={{ my: 2 }}>
                                <TextField
                                    label="Business Name"
                                    required
                                    onChange={(e) => handleChange('name', e.target.value)}
                                    error={!!errors.name}
                                    helperText={errors.name}
                                    value={formData.name}
                                />
                                <TextField
                                    select
                                    label="Category"
                                    required
                                    onChange={(e) => handleChange('category', e.target.value)}
                                    error={!!errors.category}
                                    helperText={errors.category}
                                    value={formData.category}
                                >
                                    {BusinessCategories.map((category) => (
                                        <MenuItem key={category} value={category}>
                                            {category}
                                        </MenuItem>
                                    ))}
                                </TextField>
                                <TextField
                                    label="Details / Specialisation"
                                    multiline
                                    rows={4}
                                    required
                                    onChange={(e) => handleChange('details', e.target.value)}
                                    error={!!errors.details}
                                    helperText={errors.details}
                                    value={formData.details}
                                />
                                <TextField
                                    label="Phone"
                                    required
                                    onChange={(e) => handleChange('phone', e.target.value)}
                                    error={!!errors.phone}
                                    helperText={errors.phone}
                                    value={formData.phone}
                                />
                                <TextField
                                    label="Address"
                                    required
                                    onChange={(e) => handleChange('address', e.target.value)}
                                    error={!!errors.address}
                                    helperText={errors.address}
                                    value={formData.address}
                                />
                                <TextField
                                    label="Pin Code"
                                    required
                                    type="number"
                                    onChange={(e) => handleChange('pinCode', e.target.value ? Number(e.target.value) : 0)}
                                    error={!!errors.pinCode}
                                    helperText={errors.pinCode}
                                    value={formData.pinCode || ''}
                                />
                                <TextField
                                    label="GoogleMap Link"
                                    onChange={(e) => handleChange('mapLink', e.target.value)}
                                    value={formData.mapLink}
                                />
                                <TextField
                                    label="Offer / Discount"
                                    onChange={(e) => handleChange('offer', e.target.value)}
                                    value={formData.offer}
                                />                                
                                <TextField
                                    label="Email"                                    
                                    type="email"
                                    onChange={(e) => handleChange('email', e.target.value)}
                                    value={formData.email}
                                />
                                <TextField
                                    label="Website"                                    
                                    onChange={(e) => handleChange('website', e.target.value)}
                                    value={formData.website}
                                />
                            </Stack>
                            <Divider />
                            <Stack direction='column' spacing={2} sx={{ my: 2 }}>
                                <Button style={submitButtonStyle} disabled={!isFormValid} variant="contained" type="submit">Submit</Button>
                                <StatusMessage
                                    currentStatus={businessCreationResult.status || CallStatus.NotStarted}
                                    failureMessage={BusinessServicesError.CreateBusinessError(businessCreationResult.httpStatus)}
                                    notStartedMessage={!isSubmitted ? "Please crosscheck your details before you submit." : undefined}
                                    correlationId={businessCreationResult.correlationId}
                                />
                            </Stack>
                        </List>
                    </form>
                )}
                    </CardContent>
                </Card>
            </PageContainer>
        </>
    )
}

